from flask import Flask, request, jsonify
from web3 import Web3
from eth_account import Account
from eth_account.messages import encode_defunct

app = Flask(__name__)

@app.route('/verify-signature', methods=['POST'])
def verify_signature():
    """
    Verifies an Ethereum wallet signature for authentication.
    
    Expects a JSON payload with:
    - 'message': The original string message that was signed.
    - 'signature': The hexadecimal signature string (e.g., "0x...").
    - 'address' (optional): The expected Ethereum address that signed the message.
                           If provided, the recovered address must match this.
    """
    data = request.get_json()

    if not data:
        return jsonify({"message": "Invalid JSON payload"}), 400

    message_str = data.get('message')
    signature_str = data.get('signature')
    expected_address = data.get('address') 

    if not all([message_str, signature_str]):
        return jsonify({"message": "Missing 'message' or 'signature' in request"}), 400

    try:
        # 1. Encode the message as it was signed
        # For standard EIP-191 signing (e.g., via MetaMask's personal_sign),
        # the message is typically prefixed and hashed. `encode_defunct` handles this.
        encoded_message = encode_defunct(text=message_str)

        # 2. Recover the address from the signature
        recovered_address = Account.recover_message(encoded_message, signature=signature_str)

        # Normalize addresses to checksum format for consistent comparison
        recovered_address_checksum = Web3.to_checksum_address(recovered_address)
        
        authenticated = True
        response_message = "Signature verified successfully."
        status_code = 200

        # 3. (Optional) Compare with an expected address if provided
        if expected_address:
            expected_address_checksum = Web3.to_checksum_address(expected_address)
            if recovered_address_checksum != expected_address_checksum:
                authenticated = False
                response_message = "Signature is valid, but the recovered address does not match the provided address."
                status_code = 401 # Unauthorized
            else:
                response_message = "Signature verified and matches the provided address."

        return jsonify({
            "authenticated": authenticated,
            "recovered_address": recovered_address_checksum,
            "message": response_message
        }), status_code

    except ValueError as e:
        # This typically catches invalid signatures (e.g., wrong length, malformed hex)
        return jsonify({
            "authenticated": False,
            "recovered_address": None,
            "message": f"Signature verification failed: {str(e)}. Please check signature format."
        }), 400
    except Exception as e:
        # Catch any other unexpected errors
        return jsonify({
            "authenticated": False,
            "recovered_address": None,
            "message": f"An unexpected error occurred during verification: {str(e)}"
        }), 500

